import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';

function MyVideosPage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deletingId, setDeletingId] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem('access');
    if (!token) {
      navigate('/login');
      return;
    }
    
    fetchVideos();
  }, [navigate]);

  const fetchVideos = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://localhost:8000/api/videos/', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      setVideos(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Ошибка загрузки:', error);
      setLoading(false);
    }
  };

  const handleDelete = async (videoId) => {
    if (!window.confirm('Вы уверены, что хотите удалить это видео?')) {
      return;
    }
    
    setDeletingId(videoId);
    try {
      const token = localStorage.getItem('access');
      await axios.delete(`http://localhost:8000/api/videos/${videoId}/`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      setVideos(videos.filter(v => v.id !== videoId));
      alert('Видео удалено');
    } catch (error) {
      console.error('Ошибка удаления:', error);
      alert('Не удалось удалить видео');
    } finally {
      setDeletingId(null);
    }
  };

  if (loading) {
    return <div style={{ color: 'white', textAlign: 'center', marginTop: 50 }}>Загрузка...</div>;
  }

  return (
    <div style={{ maxWidth: 800, margin: '0 auto', padding: 20 }}>
      <h1 style={{ color: 'white', marginBottom: 30 }}>Мои видео</h1>
      
      {videos.length === 0 ? (
        <div style={{ textAlign: 'center', color: '#aaa', marginTop: 50 }}>
          <p>У вас пока нет загруженных видео</p>
          <Link to="/upload" style={{ color: '#ff0000' }}>Загрузить первое видео</Link>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 15 }}>
          {videos.map(video => (
            <div key={video.id} style={{
              backgroundColor: '#1a1a1a',
              borderRadius: 12,
              padding: 15,
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              flexWrap: 'wrap',
              gap: 15
            }}>
              <div style={{ flex: 1 }}>
                <Link to={`/video/${video.id}`} style={{ textDecoration: 'none' }}>
                  <h3 style={{ color: 'white', marginBottom: 5 }}>{video.title}</h3>
                </Link>
                <p style={{ color: '#aaa', fontSize: 14, margin: 0 }}>
                  👤 {video.uploaded_by_name} • 👁️ {video.views} просмотров
                </p>
                {video.description && (
                  <p style={{ color: '#888', fontSize: 13, marginTop: 8 }}>
                    {video.description.length > 100 
                      ? video.description.slice(0, 100) + '...' 
                      : video.description}
                  </p>
                )}
              </div>
              
              <button
                onClick={() => handleDelete(video.id)}
                disabled={deletingId === video.id}
                style={{
                  backgroundColor: '#ff0000',
                  color: 'white',
                  border: 'none',
                  padding: '10px 20px',
                  borderRadius: 8,
                  cursor: deletingId === video.id ? 'not-allowed' : 'pointer',
                  fontSize: 14,
                  whiteSpace: 'nowrap'
                }}
              >
                {deletingId === video.id ? 'Удаление...' : '🗑️ Удалить'}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default MyVideosPage;
